for type_code, texts in replacements.items():
    # Replace 相性解説
    pattern_kaisetsu = re.compile(r"(## vs \[" + type_code + r"\].*?### 相性解説\n\n)(.*?)(?=\n### 一緒に楽しむコツ)", re.DOTALL)
    content = pattern_kaisetsu.sub(lambda m: m.group(1) + texts["相性解説"], content)
    
    # Replace 一緒に楽しむコツ
    pattern_kotsu = re.compile(r"(## vs \[" + type_code + r"\].*?### 一緒に楽しむコツ\n\n)(.*?)(?=\n### 摩擦ポイント)", re.DOTALL)
    content = pattern_kotsu.sub(lambda m: m.group(1) + texts["一緒に楽しむコツ"], content)
    
    # Replace 摩擦ポイント
    pattern_masatsu = re.compile(r"(## vs \[" + type_code + r"\].*?### 摩擦ポイント\n\n)(.*?)(?=\n### 目的の持ち方)", re.DOTALL)
    content = pattern_masatsu.sub(lambda m: m.group(1) + texts["摩擦ポイント"], content)

with open(file_path, "w", encoding="utf-8") as f:
    f.write(content)

print("Done")
